from __future__ import annotations

import argparse
import json
import re
from pathlib import Path
from typing import Any

import matplotlib.pyplot as plt
import pandas as pd
import seaborn as sns


DEFAULT_CRITERION_DIR = Path("target/criterion")
DEFAULT_OUTPUT_DIR = Path("target/criterion_plots")

GROUP_NAME = "world_generation_18x18_batch"

MATRIX_TYPE_ORDER = ["card_like", "balanced", "skewed", "sparse"]


def ordered_unique(values: pd.Series, preferred_order: list[str]) -> list[str]:
    present = set(values.dropna().unique())

    ordered = [value for value in preferred_order if value in present]
    extras = sorted(present - set(preferred_order))

    return ordered + extras


def parse_estimates_json(path: Path) -> dict[str, Any]:
    with path.open("r", encoding="utf-8") as f:
        return json.load(f)


def parse_params(text: str) -> dict[str, Any]:
    """
    Parses strings like:

        balanced,mass=50,num_matrices=100

    into:

        {
            "matrix_type": "balanced",
            "mass": 50,
            "num_matrices": 100,
        }
    """
    parts = text.split(",")
    matrix_type = parts[0]

    params: dict[str, Any] = {
        "matrix_type": matrix_type,
    }

    for part in parts[1:]:
        if "=" not in part:
            continue

        key, value = part.split("=", 1)
        key = key.strip()
        value = value.strip()

        if re.fullmatch(r"\d+", value):
            params[key] = int(value)
        else:
            params[key] = value

    return params


def read_criterion_results(criterion_dir: Path) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []

    group_dir = criterion_dir / GROUP_NAME
    if not group_dir.exists():
        raise FileNotFoundError(
            f"Could not find Criterion group directory: {group_dir}\n"
            f"Expected results under: {criterion_dir}"
        )

    for estimates_path in group_dir.glob("*/**/new/estimates.json"):
        relative = estimates_path.relative_to(group_dir)
        parts = relative.parts

        # Expected shape:
        # algorithm_name / parameter_string / new / estimates.json
        if len(parts) < 4:
            continue

        algorithm_name = parts[0]
        parameter_string = parts[1]

        estimates = parse_estimates_json(estimates_path)
        params = parse_params(parameter_string)

        mean_ns = estimates["mean"]["point_estimate"]
        median_ns = estimates["median"]["point_estimate"]

        row = {
            "algorithm": algorithm_name,
            "criterion_path": str(estimates_path),
            "mean_ns": mean_ns,
            "median_ns": median_ns,
            "mean_us": mean_ns / 1_000,
            "median_us": median_ns / 1_000,
            "mean_ms": mean_ns / 1_000_000,
            "median_ms": median_ns / 1_000_000,
            **params,
        }

        if "num_matrices" in row and row["num_matrices"]:
            row["mean_ms_per_matrix"] = row["mean_ms"] / row["num_matrices"]
            row["median_ms_per_matrix"] = row["median_ms"] / row["num_matrices"]
        else:
            row["mean_ms_per_matrix"] = None
            row["median_ms_per_matrix"] = None

        rows.append(row)

    if not rows:
        raise RuntimeError(f"No Criterion estimates found under {group_dir}")

    df = pd.DataFrame(rows)

    required_columns = {"algorithm", "matrix_type", "mass", "num_matrices", "mean_ms"}
    missing = required_columns - set(df.columns)
    if missing:
        raise RuntimeError(f"Parsed results are missing required columns: {sorted(missing)}")

    df["matrix_type"] = pd.Categorical(
        df["matrix_type"],
        categories=ordered_unique(df["matrix_type"], MATRIX_TYPE_ORDER),
        ordered=True,
    )

    df = df.sort_values(["matrix_type", "algorithm", "mass", "num_matrices"]).reset_index(drop=True)
    return df


def save_table(df: pd.DataFrame, output_dir: Path) -> None:
    table_columns = [
        "matrix_type",
        "algorithm",
        "mass",
        "num_matrices",
        "mean_ms",
        "median_ms",
        "mean_ms_per_matrix",
        "median_ms_per_matrix",
    ]

    table = df[table_columns].copy()

    for col in ["mean_ms", "median_ms", "mean_ms_per_matrix", "median_ms_per_matrix"]:
        table[col] = table[col].round(4)

    table.to_csv(output_dir / "world_generation_results.csv", index=False)
    table.to_markdown(output_dir / "world_generation_results.md", index=False)


def configure_style() -> None:
    sns.set_theme(style="darkgrid", context="talk")
    plt.rcParams["figure.dpi"] = 140
    plt.rcParams["savefig.dpi"] = 220


def savefig(output_dir: Path, name: str) -> None:
    path = output_dir / name
    plt.tight_layout()
    plt.savefig(path)
    plt.close()


def plot_time_by_mass(df: pd.DataFrame, output_dir: Path) -> None:
    """
    Each method, time by mass.

    Faceted by num_matrices and matrix_type, since both change runtime.
    """
    g = sns.relplot(
        data=df,
        x="mass",
        y="mean_ms",
        hue="algorithm",
        style="algorithm",
        col="num_matrices",
        row="matrix_type",
        kind="line",
        marker="o",
        facet_kws={"sharey": False, "sharex": True},
        height=4,
        aspect=1.4,
    )

    g.set_axis_labels("Mass", "Mean time per batch (ms)")
    g.set_titles(row_template="{row_name}", col_template="{col_name} matrices")
    g.figure.suptitle("World generation time by mass", y=1.02)

    g.figure.set_size_inches(16, 18)
    g.savefig(output_dir / "time_by_mass.png", dpi=220, bbox_inches="tight")
    plt.close(g.figure)


