def plot_matrix_type_comparison(df: pd.DataFrame, output_dir: Path) -> None:
    """
    Each type of matrix, time comparison at mass=50, num_matrices=100.
    """
    subset = df[(df["mass"] == 50) & (df["num_matrices"] == 100)].copy()

    if subset.empty:
        print("Skipping matrix type comparison: no rows found for mass=50, num_matrices=100")
        return

    plt.figure(figsize=(12, 8))

    ax = sns.barplot(
        data=subset,
        x="matrix_type",
        y="mean_ms",
        hue="algorithm",
    )

    ax.set_title("Time comparison by matrix type\nmass=50, num_matrices=100")
    ax.set_xlabel("Matrix type")
    ax.set_ylabel("Mean time per batch (ms)")

    savefig(output_dir, "matrix_type_comparison_mass_50_num_100.png")


