def plot_speedup_vs_mass_mixing(df: pd.DataFrame, output_dir: Path) -> None:
    """
    Computes ratio relative to mass_mixing for the same
    matrix_type/mass/num_matrices setting.

    Values > 1 mean the method is slower than mass_mixing.
    Values < 1 mean the method is faster than mass_mixing.
    """
    baseline = df[df["algorithm"] == "mass_mixing"][
        ["matrix_type", "mass", "num_matrices", "mean_ms"]
    ].rename(columns={"mean_ms": "mass_mixing_mean_ms"})

    merged = df.merge(
        baseline,
        on=["matrix_type", "mass", "num_matrices"],
        how="inner",
    )

    if merged.empty:
        print("Skipping speedup plot: no mass_mixing baseline rows found")
        return

    merged["relative_to_mass_mixing"] = merged["mean_ms"] / merged["mass_mixing_mean_ms"]

    g = sns.relplot(
        data=merged,
        x="mass",
        y="relative_to_mass_mixing",
        hue="algorithm",
        style="algorithm",
        col="num_matrices",
        row="matrix_type",
        kind="line",
        marker="o",
        facet_kws={"sharey": False, "sharex": True},
        height=4,
        aspect=1.4,
    )

    for ax in g.axes.flat:
        ax.axhline(1.0, linestyle="--", linewidth=1)

    g.set_axis_labels("Mass", "Runtime / mass_mixing runtime")
    g.set_titles(row_template="{row_name}", col_template="{col_name} matrices")
    g.figure.suptitle("Runtime relative to mass_mixing", y=1.02)

    g.figure.set_size_inches(16, 18)
    g.savefig(output_dir / "relative_to_mass_mixing.png", dpi=220, bbox_inches="tight")
    plt.close(g.figure)


def plot_heatmap(df: pd.DataFrame, output_dir: Path) -> None:
    """
    Useful compact overview: runtime by mass and num_matrices.
    """
    for matrix_type in ordered_unique(df["matrix_type"].astype(str), MATRIX_TYPE_ORDER):
        for algorithm in sorted(df["algorithm"].unique()):
            subset = df[
                (df["matrix_type"].astype(str) == matrix_type)
                & (df["algorithm"] == algorithm)
            ]

            if subset.empty:
                continue

            pivot = subset.pivot_table(
                index="mass",
                columns="num_matrices",
                values="mean_ms",
                aggfunc="mean",
            )

            plt.figure(figsize=(10, 8))
            ax = sns.heatmap(
                pivot,
                annot=True,
                fmt=".2f",
                linewidths=0.5,
                cbar_kws={"label": "Mean time per batch (ms)"},
            )

            ax.set_title(f"{algorithm}: {matrix_type} margins")
            ax.set_xlabel("Number of matrices")
            ax.set_ylabel("Mass")

            filename = f"heatmap_{algorithm}_{matrix_type}.png".replace("/", "_")
            savefig(output_dir, filename)


def plot_mass_mixing_amortization(df: pd.DataFrame, output_dir: Path) -> None:
    """
    Shows how mass_mixing amortizes its warmup cost as num_matrices increases.

    For each matrix type and mass:
    - mass_mixing is plotted as a line over num_matrices.
    - other algorithms are plotted as horizontal dotted reference lines, using
      their average per-matrix time for the same matrix_type/mass setting.
    """
    if "mass_mixing" not in set(df["algorithm"]):
        print("Skipping mass mixing amortization plot: no mass_mixing rows found")
        return

    matrix_types = ordered_unique(df["matrix_type"].astype(str), MATRIX_TYPE_ORDER)
    masses = sorted(df["mass"].unique())

    num_rows = len(matrix_types)
    num_cols = len(masses)

    fig, axes = plt.subplots(
        num_rows,
        num_cols,
        figsize=(4.5 * num_cols, 4.0 * num_rows),
        sharex=True,
        sharey=False,
        squeeze=False,
    )

    palette = dict(
        zip(
            sorted(df["algorithm"].unique()),
            sns.color_palette(n_colors=df["algorithm"].nunique()),
        )
    )

    for row_idx, matrix_type in enumerate(matrix_types):
        for col_idx, mass in enumerate(masses):
            ax = axes[row_idx][col_idx]

            subset = df[
                (df["matrix_type"].astype(str) == matrix_type)
                & (df["mass"] == mass)
            ].copy()

            if subset.empty:
                ax.set_visible(False)
                continue

            mass_mixing = subset[subset["algorithm"] == "mass_mixing"].sort_values(
                "num_matrices"
            )

            if not mass_mixing.empty:
                sns.lineplot(
                    data=mass_mixing,
                    x="num_matrices",
                    y="mean_ms_per_matrix",
                    marker="o",
                    ax=ax,
                    color=palette.get("mass_mixing"),
                    label="mass_mixing",
                )

            for algorithm in sorted(subset["algorithm"].unique()):
                if algorithm == "mass_mixing":
                    continue

                algorithm_subset = subset[subset["algorithm"] == algorithm]

                # These approaches generate each matrix independently, so their
                # per-matrix time should be roughly horizontal. Average across
                # num_matrices for this matrix_type/mass pair to reduce noise.
                reference_time = algorithm_subset["mean_ms_per_matrix"].mean()

                ax.axhline(
                    reference_time,
                    linestyle=":",
                    linewidth=2,
                    color=palette.get(algorithm),
                    label=algorithm,
                )

            ax.set_title(f"{matrix_type}, mass={mass}")
            ax.set_xlabel("Number of worlds")
            ax.set_ylabel("Mean time per world (ms)")

            # Avoid repeated legends in every subplot.
            if not (row_idx == 0 and col_idx == num_cols - 1):
                legend = ax.get_legend()
                if legend is not None:
                    legend.remove()

    handles, labels = axes[0][num_cols - 1].get_legend_handles_labels()
    fig.legend(
        handles,
        labels,
        loc="upper center",
        ncol=max(1, len(labels)),
        bbox_to_anchor=(0.5, 1.02),
    )

    fig.suptitle(
        "Mass mixing warmup amortization\n"
        "Dotted lines show independent-sampler per-world reference times",
        y=1.08,
    )

    fig.tight_layout()
    fig.savefig(
        output_dir / "mass_mixing_amortization.png",
        dpi=220,
        bbox_inches="tight",
    )
    plt.close(fig)


def plot_all(df: pd.DataFrame, output_dir: Path) -> None:
    configure_style()

    plot_time_by_mass(df, output_dir)
    plot_time_by_num_matrices(df, output_dir)
    plot_matrix_type_comparison(df, output_dir)
    plot_time_per_matrix(df, output_dir)
    plot_speedup_vs_mass_mixing(df, output_dir)
    plot_heatmap(df, output_dir)
    plot_mass_mixing_amortization(df, output_dir)


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Plot Criterion benchmark results for Monte Cardo world generation."
    )

    parser.add_argument(
        "--criterion-dir",
        type=Path,
        default=DEFAULT_CRITERION_DIR,
        help=f"Criterion results directory. Default: {DEFAULT_CRITERION_DIR}",
    )

    parser.add_argument(
        "--output-dir",
        type=Path,
        default=DEFAULT_OUTPUT_DIR,
        help=f"Directory where plots/tables should be written. Default: {DEFAULT_OUTPUT_DIR}",
    )

    args = parser.parse_args()

    args.output_dir.mkdir(parents=True, exist_ok=True)

    df = read_criterion_results(args.criterion_dir)
    save_table(df, args.output_dir)
    plot_all(df, args.output_dir)

    print(f"Read {len(df)} benchmark rows")
    print(f"Wrote plots and tables to: {args.output_dir}")

    print("\nSummary:")
    summary = (
        df.groupby(["matrix_type", "algorithm"], as_index=False)
        .agg(
            mean_ms=("mean_ms", "mean"),
            median_ms=("median_ms", "mean"),
            mean_ms_per_matrix=("mean_ms_per_matrix", "mean"),
        )
        .sort_values(["matrix_type", "mean_ms"])
    )

    with pd.option_context("display.max_rows", None, "display.max_columns", None):
        print(summary.to_string(index=False))


if __name__ == "__main__":
    main()